    /// Open file asynchronously.
    pub async fn open(cx: &Cx, path: &Path, options: OpenOptions) -> Outcome<Self, IoError>;

    /// Read into buffer.
    pub async fn read(&self, cx: &Cx, buf: &mut [u8]) -> Outcome<usize, IoError>;

    /// Write from buffer.
    pub async fn write(&self, cx: &Cx, buf: &[u8]) -> Outcome<usize, IoError>;

    /// Read at offset (pread).
    pub async fn read_at(&self, cx: &Cx, buf: &mut [u8], offset: u64) -> Outcome<usize, IoError>;

    /// Write at offset (pwrite).
    pub async fn write_at(&self, cx: &Cx, buf: &[u8], offset: u64) -> Outcome<usize, IoError>;

    /// Sync data to disk.
    pub async fn sync_data(&self, cx: &Cx) -> Outcome<(), IoError>;

    /// Sync data and metadata.
    pub async fn sync_all(&self, cx: &Cx) -> Outcome<(), IoError>;
}
